import crypto from 'crypto';

export interface Transaction {
    sender: string;
    recipient: string;
    amount: number;
    timestamp: number;
}

export class Block {
    public index: number;
    public timestamp: number;
    public transactions: Transaction[];
    public previousHash: string;
    public hash: string;
    public nonce: number;

    constructor(
        index: number,
        timestamp: number,
        transactions: Transaction[],
        previousHash: string = ''
    ) {
        this.index = index;
        this.timestamp = timestamp;
        this.transactions = transactions;
        this.previousHash = previousHash;
        this.nonce = 0;
        this.hash = this.calculateHash();
    }

    calculateHash(): string {
        return crypto
            .createHash('sha256')
            .update(
                this.index +
                this.previousHash +
                this.timestamp +
                JSON.stringify(this.transactions) +
                this.nonce
            )
            .digest('hex');
    }

    mineBlock(difficulty: number) {
        while (
            this.hash.substring(0, difficulty) !== Array(difficulty + 1).join('0')
        ) {
            this.nonce++;
            this.hash = this.calculateHash();
        }
        console.log('Block mined: ' + this.hash);
    }
}

export class Blockchain {
    public chain: Block[];
    public difficulty: number;
    public pendingTransactions: Transaction[];
    public miningReward: number;

    constructor() {
        this.chain = [this.createGenesisBlock()];
        this.difficulty = 2; // Keep it low for demo speed
        this.pendingTransactions = [];
        this.miningReward = 100;
    }

    createGenesisBlock(): Block {
        return new Block(0, Date.now(), [], '0');
    }

    getLatestBlock(): Block {
        return this.chain[this.chain.length - 1];
    }

    minePendingTransactions(miningRewardAddress: string) {
        let block = new Block(
            this.chain.length,
            Date.now(),
            this.pendingTransactions,
            this.getLatestBlock().hash
        );
        block.mineBlock(this.difficulty);

        console.log('Block successfully mined!');
        this.chain.push(block);

        this.pendingTransactions = [];
    }

    addTransaction(transaction: Transaction) {
        if (!transaction.sender || !transaction.recipient) {
            throw new Error('Transaction must include sender and recipient');
        }
        if (transaction.amount <= 0) {
            throw new Error('Transaction amount must be higher than 0');
        }

        // In a real blockchain, we would sign the transaction here.
        // For this demo, we skip signature verification.

        this.pendingTransactions.push(transaction);
    }

    getBalanceOfAddress(address: string): number {
        let balance = 0;

        for (const block of this.chain) {
            for (const trans of block.transactions) {
                if (trans.sender === address) {
                    balance -= trans.amount;
                }

                if (trans.recipient === address) {
                    balance += trans.amount;
                }
            }
        }

        return balance;
    }

    isChainValid(): boolean {
        for (let i = 1; i < this.chain.length; i++) {
            const currentBlock = this.chain[i];
            const previousBlock = this.chain[i - 1];

            if (currentBlock.hash !== currentBlock.calculateHash()) {
                return false;
            }

            if (currentBlock.previousHash !== previousBlock.hash) {
                return false;
            }
        }
        return true;
    }

    // Restore class instance from JSON object
    static fromJSON(data: any): Blockchain {
        const blockchain = new Blockchain();
        if (!data) return blockchain;

        blockchain.difficulty = data.difficulty;
        blockchain.miningReward = data.miningReward;
        blockchain.pendingTransactions = data.pendingTransactions;

        // Re-instantiate Blocks
        blockchain.chain = data.chain.map((blockData: any) => {
            const blk = new Block(
                blockData.index,
                blockData.timestamp,
                blockData.transactions,
                blockData.previousHash
            );
            blk.hash = blockData.hash;
            blk.nonce = blockData.nonce;
            return blk;
        });

        return blockchain;
    }
}

import mongoose from 'mongoose';

const MONGODB_URI = process.env.MONGODB_URI;

if (!MONGODB_URI) {
    throw new Error('Please define the MONGODB_URI environment variable inside .env.local');
}

/**
 * Global is used here to maintain a cached connection across hot reloads
 * in development. This prevents connections growing exponentially
 * during API Route usage.
 */
let cached = (global as any).mongoose;

if (!cached) {
    cached = (global as any).mongoose = { conn: null, promise: null };
}

async function dbConnect() {
    if (cached.conn) {
        return cached.conn;
    }

    if (!cached.promise) {
        const opts = {
            bufferCommands: false,
        };

        cached.promise = mongoose.connect(MONGODB_URI!, opts).then((mongoose) => {
            return mongoose;
        });
    }

    try {
        cached.conn = await cached.promise;
    } catch (e) {
        cached.promise = null;
        throw e;
    }

    return cached.conn;
}

export default dbConnect;

import { create } from 'zustand';
import { persist, createJSONStorage } from 'zustand/middleware';

export interface Transaction {
    sender: string;
    recipient: string;
    amount: number;
    timestamp: number;
}

export interface Block {
    index: number;
    timestamp: number;
    transactions: Transaction[];
    previousHash: string;
    hash: string;
    nonce: number;
}

interface AppState {
    chain: Block[];
    currentUser: string | null;
    isLoading: boolean;
    error: string | null;

    // Actions
    login: (username: string) => void;
    logout: () => void;
    fetchChain: () => Promise<void>;
    addTransaction: (tx: { sender: string; recipient: string; amount: number }) => Promise<void>;
    mineTransactions: (rewardAddress: string, rewardAmount?: number) => Promise<void>;
    getBalanceOfAddress: (address: string) => number;
}

export const useStore = create<AppState>()(
    persist(
        (set, get) => ({
            chain: [],
            currentUser: null,
            isLoading: false,
            error: null,

            login: (username) => set({ currentUser: username }),
            logout: () => set({ currentUser: null }),

            fetchChain: async () => {
                set({ isLoading: true, error: null });
                try {
                    const res = await fetch('/api/blockchain/chain');
                    if (!res.ok) throw new Error('Failed to fetch chain');
                    const data = await res.json();
                    set({ chain: data.chain, isLoading: false });
                } catch (e: any) {
                    set({ error: e.message, isLoading: false });
                }
            },

            addTransaction: async (tx) => {
                set({ isLoading: true, error: null });
                try {
                    const res = await fetch('/api/blockchain/transaction', {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify(tx),
                    });
                    if (!res.ok) {
                        const data = await res.json();
                        throw new Error(data.message || 'Failed to add transaction');
                    }
                    set({ isLoading: false });
                } catch (e: any) {
                    set({ error: e.message, isLoading: false });
                    throw e; // Re-throw to handle in UI components
                }
            },

            mineTransactions: async (rewardAddress, rewardAmount) => {
                set({ isLoading: true, error: null });
                try {
                    const res = await fetch('/api/blockchain/mine', {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({ rewardAddress, rewardAmount }),
                    });
                    const data = await res.json();
                    if (!res.ok) throw new Error(data.message || 'Failed to mine');

                    // After mining, fetch the updated chain
                    await get().fetchChain();
                    set({ isLoading: false });
                } catch (e: any) {
                    set({ error: e.message, isLoading: false });
                    throw e;
                }
            },

            getBalanceOfAddress: (address: string) => {
                let balance = 0;
                const { chain } = get();

                for (const block of chain) {
                    for (const trans of block.transactions) {
                        if (trans.sender === address) {
                            balance -= trans.amount;
                        }
                        if (trans.recipient === address) {
                            balance += trans.amount;
                        }
                    }
                }
                return balance;
            }
        }),
        {
            name: 'ebanking-session',
            storage: createJSONStorage(() => localStorage),
            partialize: (state) => ({ currentUser: state.currentUser }), // Only persist currentUser
        }
    )
);
